import java.io.*;
import java.util.Base64;

public class SecureDeserializationDemo {

    public static void main(String[] args) {
        String userInput = "serializedData"; // User input containing serialized data

        try {
            byte[] serializedData = Base64.getDecoder().decode(userInput);

            Object obj = deserializeObject(serializedData);

            if (obj instanceof String) {
                System.out.println("Deserialized object: " + obj.toString());
            } else {
                System.out.println("Invalid object type after deserialization.");
            }

        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }

    private static Object deserializeObject(byte[] serializedData) throws IOException, ClassNotFoundException {
        ByteArrayInputStream bis = new ByteArrayInputStream(serializedData);

        try (ObjectInputStream ois = new ObjectInputStream(bis)) {
            return ois.readObject();
        }
    }
}

